SELECT ts_b.geometry_building_type_recs, date_trunc('month', date_add('second', -900, ts_b.timestamp)) AS timestamp, count(distinct(bs.bldg_id)) AS sample_count, (count(distinct(bs.bldg_id)) * sum(bs.weight)) / CAST(sum(1) AS DECIMAL) AS units_count, sum(1) / CAST(count(distinct(bs.bldg_id)) AS DECIMAL) AS rows_per_sample, sum(ts_b."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__baseline", sum(ts_u."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(ts_b."out.electricity.total.energy_consumption", 0) - coalesce(ts_u."out.electricity.total.energy_consumption", 0)) * bs.weight) AS "electricity.total.energy_consumption__savings", sum(ts_b."out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__baseline", sum(ts_u."out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__upgrade", sum((coalesce(ts_b."out.natural_gas.total.energy_consumption", 0) - coalesce(ts_u."out.natural_gas.total.energy_consumption", 0)) * bs.weight) AS "natural_gas.total.energy_consumption__savings" FROM (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp AS timestamp, bs."in.geometry_building_type_recs" AS geometry_building_type_recs, resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" AS "out.electricity.total.energy_consumption", resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" AS "out.natural_gas.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = resstock_2024_amy2018_release_2_by_state_vu.bldg_id AND bs.upgrade = 0 WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade = 0 AND resstock_2024_amy2018_release_2_by_state_vu.state IN ('CO', 'WY') AND resstock_2024_amy2018_release_2_by_state_vu.bldg_id IN (SELECT up.bldg_id FROM resstock_2024_amy2018_release_2_metadata AS up WHERE up.upgrade IN (1) AND up.applicability = true GROUP BY up.bldg_id HAVING count(distinct(up.upgrade)) = 1)) AS ts_b JOIN (SELECT resstock_2024_amy2018_release_2_by_state_vu.bldg_id AS bldg_id, resstock_2024_amy2018_release_2_by_state_vu.timestamp AS timestamp, bs."in.geometry_building_type_recs" AS geometry_building_type_recs, resstock_2024_amy2018_release_2_by_state_vu."out.electricity.total.energy_consumption" AS "out.electricity.total.energy_consumption", resstock_2024_amy2018_release_2_by_state_vu."out.natural_gas.total.energy_consumption" AS "out.natural_gas.total.energy_consumption" FROM resstock_2024_amy2018_release_2_by_state_vu JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = resstock_2024_amy2018_release_2_by_state_vu.bldg_id AND bs.upgrade = 0 WHERE resstock_2024_amy2018_release_2_by_state_vu.upgrade = 1 AND resstock_2024_amy2018_release_2_by_state_vu.state IN ('CO', 'WY') AND resstock_2024_amy2018_release_2_by_state_vu.bldg_id IN (SELECT up.bldg_id FROM resstock_2024_amy2018_release_2_metadata AS up WHERE up.upgrade IN (1) AND up.applicability = true GROUP BY up.bldg_id HAVING count(distinct(up.upgrade)) = 1)) AS ts_u ON ts_b.bldg_id = ts_u.bldg_id AND ts_b.timestamp = ts_u.timestamp JOIN resstock_2024_amy2018_release_2_metadata AS bs ON bs.bldg_id = ts_b.bldg_id AND bs.upgrade = 0 GROUP BY 1, 2 ORDER BY 1, 2